     1|/**
     2| * BLOCK 27 — Owner CRM landing (IVX → CRM).
     3| *
     4| * This route replaces the old debug/duplicate `index` tab. It is the dedicated
     5| * owner-only CRM hub for all tokenized deals: Capital, Sales, and Execution
     6| * sections that open the existing owner-gated CRM screens, with live dashboard
     7| * badge counts. Hidden from public/investor/buyer roles at the tab layer; the
     8| * screen itself also guards content so a non-owner who deep-links here sees an
     9| * access-restricted state instead of CRM data.
    10| *
    11| * Build 35 fix: each top stat tile loads independently with its own cached-first
    12| * value, skeleton, and error state. A single slow or failing endpoint no longer
    13| * blocks all five tiles from rendering.
    14| */
    15|import React, { useMemo, useCallback, useState, useEffect } from 'react';
    16|import {
    17|  View,
    18|  Text,
    19|  StyleSheet,
    20|  ScrollView,
    21|  TouchableOpacity,
    22|  RefreshControl,
    23|  ActivityIndicator,
    24|} from 'react-native';
    25|import { SafeAreaView } from 'react-native-safe-area-context';
    26|import { useRouter } from 'expo-router';
    27|import { useQuery, useQueryClient } from '@tanstack/react-query';
    28|import AsyncStorage from '@react-native-async-storage/async-storage';
    29|import {
    30|  Users,
    31|  Building2,
    32|  Handshake,
    33|  Landmark,
    34|  Send,
    35|  Megaphone,
    36|  Gauge,
    37|  Crosshair,
    38|  GitBranch,
    39|  ClipboardList,
    40|  Target,
    41|  ChevronRight,
    42|  ShieldAlert,
    43|  Lock,
    44|  AlertCircle,
    45|  type LucideIcon,
    46|} from 'lucide-react-native';
    47|import Colors from '@/constants/colors';
    48|import { useAuth } from '@/lib/auth-context';
    49|import { isOpenAccessModeEnabled } from '@/lib/open-access';
    50|import { listInvestors } from '@/src/modules/ivx-developer/investorCrmService';
    51|import { listPipelineEntries } from '@/src/modules/ivx-developer/capitalPipelineService';
    52|import { listOutreachMessages } from '@/src/modules/ivx-developer/outreachService';
    53|import { listDeals } from '@/src/modules/ivx-developer/dealTrackingService';
    54|import { getDealMatching } from '@/src/modules/ivx-developer/dealMatchingService';
    55|
    56|type CrmRoute =
    57|  | '/ivx/investors'
    58|  | '/ivx/capital-network'
    59|  | '/ivx/capital-outreach'
    60|  | '/ivx/outreach'
    61|  | '/ivx/lead-scoring'
    62|  | '/ivx/deal-matching'
    63|  | '/ivx/capital-pipeline'
    64|  | '/ivx/deal-tracking'
    65|  | '/ivx/opportunity-engine';
    66|
    67|type CrmLink = {
    68|  label: string;
    69|  description: string;
    70|  icon: LucideIcon;
    71|  route: CrmRoute;
    72|  testID: string;
    73|};
    74|
    75|type CrmSection = {
    76|  title: string;
    77|  accent: string;
    78|  links: CrmLink[];
    79|};
    80|
    81|type BadgeKey = 'investors' | 'buyers' | 'activeDeals' | 'pendingOutreach' | 'matchesToday';
    82|
    83|type BadgeConfig = {
    84|  key: BadgeKey;
    85|  label: string;
    86|  cacheKey: string;
    87|  queryKey: string[];
    88|};
    89|
    90|const CRM_SECTIONS: CrmSection[] = [
    91|  {
    92|    title: 'Capital',
    93|    accent: Colors.gold,
    94|    links: [
    95|      { label: 'Investors', description: 'Investor CRM & relationships', icon: Users, route: '/ivx/investors', testID: 'crm-link-investors' },
    96|      { label: 'Buyers', description: 'Buyer prospects & matching', icon: Building2, route: '/ivx/capital-network', testID: 'crm-link-buyers' },
    97|      { label: 'Partners', description: 'Strategic partners network', icon: Handshake, route: '/ivx/capital-network', testID: 'crm-link-partners' },
    98|      { label: 'Lenders', description: 'Financing & private credit', icon: Landmark, route: '/ivx/capital-network', testID: 'crm-link-lenders' },
    99|    ],
   100|  },
   101|  {
   102|    title: 'Sales',
   103|    accent: Colors.info,
   104|    links: [
   105|      { label: 'Outreach', description: 'Capital outreach strategy', icon: Send, route: '/ivx/capital-outreach', testID: 'crm-link-outreach' },
   106|      { label: 'Campaigns', description: 'Automated message campaigns', icon: Megaphone, route: '/ivx/outreach', testID: 'crm-link-campaigns' },
   107|      { label: 'Lead Scores', description: 'Hot / warm / cold scoring', icon: Gauge, route: '/ivx/lead-scoring', testID: 'crm-link-lead-scores' },
   108|      { label: 'Matching', description: 'Deal-to-investor matching', icon: Crosshair, route: '/ivx/deal-matching', testID: 'crm-link-matching' },
   109|    ],
   110|  },
   111|  {
   112|    title: 'Execution',
   113|    accent: Colors.success,
   114|    links: [
   115|      { label: 'Pipeline', description: 'Capital pipeline stages', icon: GitBranch, route: '/ivx/capital-pipeline', testID: 'crm-link-pipeline' },
   116|      { label: 'Deal Tracking', description: 'Lifecycle & outcome metrics', icon: ClipboardList, route: '/ivx/deal-tracking', testID: 'crm-link-deal-tracking' },
   117|      { label: 'Active Opportunities', description: "Today's best opportunities", icon: Target, route: '/ivx/opportunity-engine', testID: 'crm-link-active-opportunities' },
   118|    ],
   119|  },
   120|];
   121|
   122|const BADGE_CONFIG: BadgeConfig[] = [
   123|  { key: 'investors', label: 'Investors', cacheKey: 'ivx-crm-badge-investors', queryKey: ['crm-badge', 'investors'] },
   124|  { key: 'buyers', label: 'Buyers', cacheKey: 'ivx-crm-badge-buyers', queryKey: ['crm-badge', 'buyers'] },
   125|  { key: 'activeDeals', label: 'Active Deals', cacheKey: 'ivx-crm-badge-active-deals', queryKey: ['crm-badge', 'active-deals'] },
   126|  { key: 'pendingOutreach', label: 'Pending Outreach', cacheKey: 'ivx-crm-badge-pending-outreach', queryKey: ['crm-badge', 'pending-outreach'] },
   127|  { key: 'matchesToday', label: 'Matches Today', cacheKey: 'ivx-crm-badge-matches-today', queryKey: ['crm-badge', 'matches-today'] },
   128|];
   129|
   130|const CACHE_VERSION = 'v1';
   131|
   132|type CachedBadges = Partial<Record<BadgeKey, number>>;
   133|
   134|async function loadCachedBadges(): Promise<CachedBadges> {
   135|  const result: CachedBadges = {};
   136|  try {
   137|    const entries = await AsyncStorage.multiGet(
   138|      BADGE_CONFIG.map((c) => `${c.cacheKey}:${CACHE_VERSION}`),
   139|    );
   140|    for (let i = 0; i < entries.length; i += 1) {
   141|      const [, raw] = entries[i];
   142|      if (!raw) continue;
   143|      const parsed = Number(raw);
   144|      if (Number.isFinite(parsed)) {
   145|        result[BADGE_CONFIG[i].key] = parsed;
   146|      }
   147|    }
   148|  } catch {
   149|    // cache read is best-effort
   150|  }
   151|  return result;
   152|}
   153|
   154|async function saveCachedBadge(cacheKey: string, value: number): Promise<void> {
   155|  try {
   156|    await AsyncStorage.setItem(`${cacheKey}:${CACHE_VERSION}`, String(value));
   157|  } catch {
   158|    // cache write is best-effort
   159|  }
   160|}
   161|
   162|async function fetchInvestorsBadge(): Promise<number> {
   163|  const result = await listInvestors();
   164|  const value = result.summary?.total ?? result.investors.length;
   165|  await saveCachedBadge(BADGE_CONFIG[0].cacheKey, value);
   166|  return value;
   167|}
   168|
   169|async function fetchBuyersBadge(): Promise<number> {
   170|  const result = await listPipelineEntries();
   171|  const value = result.summary?.activeBuyers ?? 0;
   172|  await saveCachedBadge(BADGE_CONFIG[1].cacheKey, value);
   173|  return value;
   174|}
   175|
   176|async function fetchActiveDealsBadge(): Promise<number> {
   177|  const result = await listDeals();
   178|  const open = result.metrics?.byStatus?.open ?? 0;
   179|  const inProgress = result.metrics?.byStatus?.in_progress ?? 0;
   180|  const value = open + inProgress;
   181|  await saveCachedBadge(BADGE_CONFIG[2].cacheKey, value);
   182|  return value;
   183|}
   184|
   185|async function fetchPendingOutreachBadge(): Promise<number> {
   186|  const result = await listOutreachMessages();
   187|  const value = result.summary?.pendingApproval ?? 0;
   188|  await saveCachedBadge(BADGE_CONFIG[3].cacheKey, value);
   189|  return value;
   190|}
   191|
   192|async function fetchMatchesTodayBadge(): Promise<number> {
   193|  const result = await getDealMatching();
   194|  const value = result?.summary?.strongMatches ?? 0;
   195|  await saveCachedBadge(BADGE_CONFIG[4].cacheKey, value);
   196|  return value;
   197|}
   198|
   199|const BADGE_FETCHERS: Record<BadgeKey, () => Promise<number>> = {
   200|  investors: fetchInvestorsBadge,
   201|  buyers: fetchBuyersBadge,
   202|  activeDeals: fetchActiveDealsBadge,
   203|  pendingOutreach: fetchPendingOutreachBadge,
   204|  matchesToday: fetchMatchesTodayBadge,
   205|};
   206|
   207|export default function CrmScreen() {
   208|  const router = useRouter();
   209|  const queryClient = useQueryClient();
   210|  const { profileData } = useAuth();
   211|  const [cachedBadges, setCachedBadges] = useState<CachedBadges>({});
   212|  const [isCacheLoaded, setIsCacheLoaded] = useState(false);
   213|
   214|  useEffect(() => {
   215|    let cancelled = false;
   216|    loadCachedBadges().then((badges) => {
   217|      if (cancelled) return;
   218|      setCachedBadges(badges);
   219|      setIsCacheLoaded(true);
   220|    });
   221|    return () => {
   222|      cancelled = true;
   223|    };
   224|  }, []);
   225|
   226|  const isOwner = useMemo(() => {
   227|    // Mirror useAdminGuard: open-access builds (dev/preview) bypass the owner
   228|    // gate so Admin → Members and CRM routes are reachable without a session.
   229|    // Production builds keep the strict owner/admin role check.
   230|    if (isOpenAccessModeEnabled()) return true;
   231|    const role = ((profileData as { role?: string } | null)?.role ?? '').toLowerCase();
   232|    return role === 'owner' || role === 'admin';
   233|  }, [profileData]);
   234|
   235|  const openRoute = useCallback(
   236|    (route: CrmRoute) => {
   237|      router.push(route as never);
   238|    },
   239|    [router],
   240|  );
   241|
   242|  const handleRefresh = useCallback(() => {
   243|    queryClient.invalidateQueries({ queryKey: ['crm-badge'] });
   244|  }, [queryClient]);
   245|
   246|  const isRefetching = useMemo(() => {
   247|    const states = BADGE_CONFIG.map((c) => queryClient.getQueryState(c.queryKey));
   248|    return states.some((s) => s?.fetchStatus === 'fetching');
   249|  }, [queryClient]);
   250|
   251|  if (!isOwner) {
   252|    return (
   253|      <SafeAreaView style={styles.container} edges={['top']}>
   254|        <View style={styles.restricted} testID="crm-access-restricted">
   255|          <View style={styles.restrictedIcon}>
   256|            <Lock color={Colors.gold} size={30} strokeWidth={2.2} />
   257|          </View>
   258|          <Text style={styles.restrictedTitle}>Owner access only</Text>
   259|          <Text style={styles.restrictedBody}>
   260|            The CRM is restricted to the IVX owner. Sign in with an owner account to manage capital, sales, and execution.
   261|          </Text>
   262|        </View>
   263|      </SafeAreaView>
   264|    );
   265|  }
   266|
   267|  return (
   268|    <SafeAreaView style={styles.container} edges={['top']}>
   269|      <ScrollView
   270|        contentContainerStyle={styles.content}
   271|        showsVerticalScrollIndicator={false}
   272|        refreshControl={
   273|          <RefreshControl
   274|            refreshing={isRefetching}
   275|            onRefresh={handleRefresh}
   276|            tintColor={Colors.gold}
   277|          />
   278|        }
   279|      >
   280|        <View style={styles.header}>
   281|          <View style={styles.headerBadge}>
   282|            <ShieldAlert color={Colors.black} size={13} strokeWidth={2.6} />
   283|            <Text style={styles.headerBadgeText}>OWNER</Text>
   284|          </View>
   285|          <Text style={styles.title}>CRM</Text>
   286|          <Text style={styles.subtitle}>Capital deployment across all tokenized deals</Text>
   287|        </View>
   288|
   289|        <View style={styles.statsRow}>
   290|          {BADGE_CONFIG.map((config) => (
   291|            <StatTile
   292|              key={config.key}
   293|              config={config}
   294|              cachedValue={cachedBadges[config.key]}
   295|              isCacheLoaded={isCacheLoaded}
   296|            />
   297|          ))}
   298|        </View>
   299|
   300|        {CRM_SECTIONS.map((section) => (
   301|          <View key={section.title} style={styles.section}>
   302|            <View style={styles.sectionHeader}>
   303|              <View style={[styles.sectionDot, { backgroundColor: section.accent }]} />
   304|              <Text style={styles.sectionTitle}>{section.title}</Text>
   305|            </View>
   306|            <View style={styles.card}>
   307|              {section.links.map((link, idx) => {
   308|                const Icon = link.icon;
   309|                return (
   310|                  <TouchableOpacity
   311|                    key={link.testID}
   312|                    style={[styles.row, idx === section.links.length - 1 && styles.rowLast]}
   313|                    onPress={() => openRoute(link.route)}
   314|                    activeOpacity={0.7}
   315|                    accessibilityRole="button"
   316|                    accessibilityLabel={`Open ${link.label}`}
   317|                    testID={link.testID}
   318|                  >
   319|                    <View style={[styles.rowIcon, { borderColor: section.accent }]}>
   320|                      <Icon color={section.accent} size={19} strokeWidth={2.2} />
   321|                    </View>
   322|                    <View style={styles.rowText}>
   323|                      <Text style={styles.rowLabel}>{link.label}</Text>
   324|                      <Text style={styles.rowDescription}>{link.description}</Text>
   325|                    </View>
   326|                    <ChevronRight color={Colors.textTertiary} size={18} />
   327|                  </TouchableOpacity>
   328|                );
   329|              })}
   330|            </View>
   331|          </View>
   332|        ))}
   333|
   334|        <View style={styles.footerSpace} />
   335|      </ScrollView>
   336|    </SafeAreaView>
   337|  );
   338|}
   339|
   340|function StatTile({
   341|  config,
   342|  cachedValue,
   343|  isCacheLoaded,
   344|}: {
   345|  config: BadgeConfig;
   346|  cachedValue: number | undefined;
   347|  isCacheLoaded: boolean;
   348|}) {
   349|  const query = useQuery({
   350|    queryKey: config.queryKey,
   351|    queryFn: BADGE_FETCHERS[config.key],
   352|    enabled: true,
   353|    staleTime: 1000 * 30,
   354|    refetchOnWindowFocus: true,
   355|    placeholderData: (prev) => prev,
   356|  });
   357|
   358|  const isLoading = query.isLoading && query.data === undefined;
   359|  const hasError = query.isError && query.data === undefined && cachedValue === undefined;
   360|  const value = query.data ?? cachedValue ?? 0;
   361|  const showSkeleton = isLoading && cachedValue === undefined;
   362|  const showRefetchIndicator = query.isRefetching && !showSkeleton;
   363|
   364|  return (
   365|    <View style={styles.statTile} testID={`crm-stat-${config.key}`}>
   366|      {showSkeleton ? (
   367|        <View style={styles.skeletonValue} />
   368|      ) : hasError ? (
   369|        <AlertCircle color={Colors.warning} size={22} />
   370|      ) : (
   371|        <Text style={styles.statValue}>{value}</Text>
   372|      )}
   373|      <Text style={styles.statLabel}>{config.label}</Text>
   374|      {showRefetchIndicator && (
   375|        <View style={styles.refetchDot} />
   376|      )}
   377|      {!isCacheLoaded && !showSkeleton && (
   378|        <ActivityIndicator color={Colors.gold} size="small" style={styles.miniLoader} />
   379|      )}
   380|    </View>
   381|  );
   382|}
