     9|import { getDirectApiBaseUrl } from '@/lib/api-base';
    10|import { assertOwnerSessionAccessToken } from '@/src/modules/ivx-owner-ai/services/ownerSessionPreflight';
    11|
    12|export type InvestorSource =
    13|  | 'owner_entered'
    14|  | 'submitted_form'
    15|  | 'crm_import'
    16|  | 'public_source'
